@import "tailwindcss";

/* ═══════════════════════════════════════════════════════════
   DESIGN SYSTEM — RoyallAzz (based on CitedBy.io)
   Dual theme: Light (Frase.io style) + Dark (Linear/Vercel)
   ═══════════════════════════════════════════════════════════ */

/* ═══ LIGHT MODE (default) ═══ */
:root {
  --bg-base:        #FAFAF8;
  --bg-surface:     #FFFFFF;
  --bg-elevated:    #F5F5F3;
  --bg-overlay:     #E5E7EB;
  --bg-sidebar:     #FFFFFF;

  --border-default: #E5E7EB;
  --border-subtle:  #F0F0EE;
  --border-strong:  #D1D5DB;

  --text-primary:   #1A1A1A;
  --text-secondary: #6B7280;
  --text-tertiary:  #9CA3AF;
  --text-disabled:  #D1D5DB;

  --accent:         #059669;
  --accent-hover:   #047857;
  --accent-subtle:  rgba(5, 150, 105, 0.08);
  --accent-text:    #059669;

  --success:        #16A34A;
  --success-subtle: rgba(22, 163, 74, 0.08);
  --warning:        #D97706;
  --warning-subtle: rgba(217, 119, 6, 0.08);
  --error:          #DC2626;
  --error-subtle:   rgba(220, 38, 38, 0.08);

  --glass-bg:            rgba(255, 255, 255, 0.8);
  --glass-bg-strong:     rgba(255, 255, 255, 0.9);
  --glass-border:        rgba(0, 0, 0, 0.06);
  --glass-border-hover:  rgba(0, 0, 0, 0.1);
  --glass-surface:       rgba(0, 0, 0, 0.02);
  --glass-surface-hover: rgba(0, 0, 0, 0.04);
  --glass-active:        rgba(0, 0, 0, 0.06);

  color-scheme: light;
}

/* ═══ DARK MODE ═══ */
.dark {
  --bg-base:        #09090B;
  --bg-surface:     #18181B;
  --bg-elevated:    #27272A;
  --bg-overlay:     #3F3F46;
  --bg-sidebar:     #0F0F11;

  --border-default: #27272A;
  --border-subtle:  #1E1E22;
  --border-strong:  #3F3F46;

  --text-primary:   #FAFAFA;
  --text-secondary: #A1A1AA;
  --text-tertiary:  #71717A;
  --text-disabled:  #52525B;

  --accent:         #10B981;
  --accent-hover:   #059669;
  --accent-subtle:  rgba(16, 185, 129, 0.1);
  --accent-text:    #34D399;

  --success:        #22C55E;
  --success-subtle: rgba(34, 197, 94, 0.1);
  --warning:        #F59E0B;
  --warning-subtle: rgba(245, 158, 11, 0.1);
  --error:          #EF4444;
  --error-subtle:   rgba(239, 68, 68, 0.1);

  --glass-bg:            rgba(9, 9, 11, 0.8);
  --glass-bg-strong:     rgba(9, 9, 11, 0.9);
  --glass-border:        rgba(255, 255, 255, 0.06);
  --glass-border-hover:  rgba(255, 255, 255, 0.1);
  --glass-surface:       rgba(255, 255, 255, 0.04);
  --glass-surface-hover: rgba(255, 255, 255, 0.06);
  --glass-active:        rgba(255, 255, 255, 0.08);

  color-scheme: dark;
}

/* ═══ FOUNDATIONS ═══ */
html, body {
  margin: 0; padding: 0; min-height: 100%;
  background-color: var(--bg-base);
  color: var(--text-primary);
  font-family: 'Geist Sans', 'Inter', system-ui, -apple-system, sans-serif;
  line-height: 1.45;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-rendering: optimizeLegibility;
}

code, pre, .font-mono, kbd {
  font-family: 'Geist Mono', 'SF Mono', Consolas, monospace;
}

h1, h2, h3, h4, h5, h6 {
  font-family: 'Geist Sans', 'Inter', system-ui, sans-serif;
  letter-spacing: -0.025em;
}

::selection { background-color: var(--accent); color: white; }

/* ═══ SCROLLBAR ═══ */
* { scrollbar-width: thin; scrollbar-color: var(--border-default) transparent; }
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border-default); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: var(--border-strong); }

*:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
  border-radius: 4px;
}

/* ═══ ANIMATIONS ═══ */
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}
.page-enter { animation: fadeInUp 0.2s ease-out; }

@keyframes shimmer {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}
.skeleton-shimmer {
  background: linear-gradient(90deg, var(--glass-surface) 25%, var(--glass-surface-hover) 50%, var(--glass-surface) 75%);
  background-size: 200% 100%;
  animation: shimmer 1.8s ease-in-out infinite;
}

@keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
@keyframes zoom-in { from { transform: scale(0.95); } to { transform: scale(1); } }
@keyframes slide-in-from-bottom { from { transform: translateY(8px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
.animate-in { animation: fade-in 0.5s ease-out, zoom-in 0.3s ease-out; }
.animate-slide-up { animation: slide-in-from-bottom 0.3s ease-out; }

.stagger-1 { animation-delay: 50ms; }
.stagger-2 { animation-delay: 100ms; }
.stagger-3 { animation-delay: 150ms; }
.stagger-4 { animation-delay: 200ms; }
.stagger-5 { animation-delay: 250ms; }
.stagger-6 { animation-delay: 300ms; }

@keyframes staggerSlideUp {
  from { opacity: 0; transform: translateY(12px); }
  to { opacity: 1; transform: translateY(0); }
}
.stagger-enter { opacity: 0; animation: staggerSlideUp 0.3s ease-out forwards; }

/* ═══ MICRO-INTERACTIONS ═══ */
.hover-lift {
  transition: transform 0.2s ease-out, box-shadow 0.2s ease-out, border-color 0.2s ease-out;
}
.hover-lift:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 25px -5px rgba(0, 0, 0, 0.15);
}
.dark .hover-lift:hover {
  box-shadow: 0 8px 25px -5px rgba(0, 0, 0, 0.3);
}
.press-effect:active { transform: scale(0.98); }
.glow-accent { transition: box-shadow 0.3s ease-out; }
.glow-accent:hover { box-shadow: 0 0 20px -5px var(--accent); }

@keyframes smoothSpin {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}
.smooth-spin { animation: smoothSpin 0.8s linear infinite; }

/* ═══ UTILITIES ═══ */
.ninja-card {
  background: var(--glass-surface);
  border: 1px solid var(--glass-border);
  border-radius: 0.75rem;
  backdrop-filter: blur(4px);
  transition: border-color 0.2s, box-shadow 0.2s, background 0.2s;
}
.ninja-card:hover {
  border-color: var(--glass-border-hover);
  background: var(--glass-surface-hover);
}

.gradient-text {
  background: linear-gradient(135deg, var(--accent), var(--accent-text));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

/* ═══ ACCESSIBILITY ═══ */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
  .page-enter, .animate-in, .animate-slide-up, .stagger-enter {
    animation: none !important; opacity: 1 !important; transform: none !important;
  }
  .skeleton-shimmer { animation: none !important; background: var(--bg-elevated) !important; }
  .hover-lift:hover { transform: none !important; }
}


