                }`}
              >
                {t === 'stamp' ? 'Tampons' : 'Points'}
              </button>
            ))}
          </div>
        </div>

        <Input label={form.type === 'stamp' ? 'Tampons requis' : 'Points objectif'} type="number" min={1}
          value={String(form.target)} onChange={e => update('target', parseInt(e.target.value) || 1)} />

        <Input label="Bonus de bienvenue" type="number" min={0}
          value={String(form.welcomeBonus)} onChange={e => update('welcomeBonus', parseInt(e.target.value) || 0)} />

