389→**Step 1: Create theme context**
390→
391→```typescript
392→// src/lib/theme-context.tsx
393→'use client';
394→
395→import { createContext, useContext, useEffect, useState, type ReactNode } from 'react';
396→
397→type Theme = 'light' | 'dark';
398→
399→interface ThemeContextValue {
400→  theme: Theme;
401→  toggleTheme: () => void;
402→}
403→
404→const ThemeContext = createContext<ThemeContextValue>({
405→  theme: 'light',
406→  toggleTheme: () => {},
407→});
408→
409→const STORAGE_KEY = 'royallazz-theme';
410→
411→function getInitialTheme(): Theme {
412→  if (typeof window === 'undefined') return 'light';
413→  const stored = localStorage.getItem(STORAGE_KEY);
414→  if (stored === 'light' || stored === 'dark') return stored;
415→  return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
416→}
417→
418→export function ThemeProvider({ children }: { children: ReactNode }) {
419→  const [theme, setTheme] = useState<Theme>(getInitialTheme);
420→
421→  useEffect(() => {
422→    const root = document.documentElement;
423→    root.classList.toggle('dark', theme === 'dark');
424→    localStorage.setItem(STORAGE_KEY, theme);
425→  }, [theme]);
426→
427→  const toggleTheme = () => setTheme(prev => (prev === 'light' ? 'dark' : 'light'));
428→
429→  return (
430→    <ThemeContext.Provider value={{ theme, toggleTheme }}>
431→      {children}
432→    </ThemeContext.Provider>
433→  );
434→}
435→
436→export function useTheme() {
437→  return useContext(ThemeContext);
438→}
439→```
