 563→
 564→interface ButtonProps {
 565→  children: ReactNode;
 566→  variant?: 'primary' | 'secondary' | 'ghost' | 'danger';
 567→  size?: 'sm' | 'md' | 'lg';
 568→  icon?: React.ElementType;
