 579→  secondary: 'bg-transparent text-[var(--text-secondary)] border border-[var(--border-default)] hover:border-[var(--border-strong)] hover:text-[var(--text-primary)]',
 580→  ghost: 'bg-transparent text-[var(--text-secondary)] hover:bg-[var(--glass-active)] hover:text-[var(--text-primary)]',
 581→  danger: 'bg-transparent text-[var(--error)] border border-[var(--error)]/20 hover:bg-[var(--error-subtle)]',
 582→};
 583→
 584→const SIZE = {
 585→  sm: 'text-[13px] px-3 py-1.5 rounded-lg gap-1.5',
 586→  md: 'text-sm px-4 py-2 rounded-lg gap-2',
 587→  lg: 'text-sm px-5 py-2.5 rounded-lg gap-2',
 588→};
 589→
 590→const Spinner = () => (
 591→  <svg className="animate-spin w-4 h-4" viewBox="0 0 24 24" fill="none">
 592→    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3" />
 593→    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
 594→  </svg>
 595→);
 596→
 597→export default function Button({
 598→  children, variant = 'primary', size = 'md', icon: Icon,
 599→  iconPosition = 'left', loading = false, disabled = false,
 600→  onClick, className = '', type = 'button',
 601→}: ButtonProps) {
 602→  return (
 603→    <button
 604→      type={type}
 605→      onClick={onClick}
 606→      disabled={disabled || loading}
 607→      className={cn(
 608→        'inline-flex items-center justify-center font-medium transition-all duration-150 press-effect',
 609→        disabled || loading ? 'cursor-not-allowed' : 'cursor-pointer',
 610→        VARIANT[variant], SIZE[size], className,
