1151→import { createServerClient } from '@supabase/ssr';
1152→import { cookies } from 'next/headers';
1153→import type { Database } from './types';
1154→
1155→export async function createServerSupabase() {
1156→  const cookieStore = await cookies();
1157→  return createServerClient<Database>(
1158→    process.env.NEXT_PUBLIC_SUPABASE_URL!,
1159→    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
1160→    {
1161→      cookies: {
1162→        getAll() { return cookieStore.getAll(); },
1163→        setAll(cookiesToSet) {
1164→          cookiesToSet.forEach(({ name, value, options }) => {
1165→            try { cookieStore.set(name, value, options); } catch {}
1166→          });
1167→        },
1168→      },
1169→    },
1170→  );
1171→}
